// ---------------------------------------------------------------------------
// Imports
// ---------------------------------------------------------------------------

import 'dart:typed_data';

// ---------------------------------------------------------------------------
// Key Cache Entry
// ---------------------------------------------------------------------------

class KeyCacheEntry {
  // ---------------------------------------------------------------------------
  // Constructor
  // ---------------------------------------------------------------------------

  const KeyCacheEntry({
    required this.key,
    required this.createdAt,
  });

  // ---------------------------------------------------------------------------
  // Properties
  // ---------------------------------------------------------------------------

  final Uint8List key;
  final DateTime createdAt;

  // ---------------------------------------------------------------------------
  // Helpers
  // ---------------------------------------------------------------------------

  Duration get age => DateTime.now().difference(createdAt);
}